                  >
                    <div className="absolute -top-4 -left-4 opacity-10 dark:opacity-20">
                      <Quote size={windowWidth < 640 ? 40 : 60} className="text-primary dark:text-primary-light" />
                    </div>

                    <div className="relative z-10 h-full flex flex-col">
